/**
 * App.jsx — Corridor Planner v4 (Refactored)
 *
 * State: Zustand (useAppStore) — replaces ~50 useState
 * Cache: TanStack Query — AI calls, geocoding
 * Map: InteractiveMap component — extracted Leaflet logic
 * Theme: CSS variables + Tailwind (dual-mode)
 * Validation: Zod schemas in store
 */
import { useState, useRef, useEffect, useMemo } from 'react'
import { QueryClientProvider } from '@tanstack/react-query'
import 'leaflet/dist/leaflet.css'
import './styles/theme.css'

import useAppStore, { useActiveEvent, useRawIncidents, autoDetectType } from './store/useAppStore.js'
import { queryClient, testAIConnection, useBriefAnalysis, useChatSend } from './lib/api.js'
import InteractiveMap, { DrawingsList } from './components/Map/InteractiveMap.jsx'
import SharedView from './components/SharedView.jsx'
import {
  ICON_MAP, SEVERITY, BASE_LAYERS, INC_TYPES, SEV_LEVELS, EVENT_TYPES,
  computeStats, computeTypeCounts, buildOverpassQuery, decodeShare,
  encodeShare, eventToGeoJSON, eventToCSV, eventToReport, setGeoBias
} from './data/events.js'
import { t, LANGS } from './data/i18n.js'

const dlF = (c, f, m = 'text/plain') => { const b = new Blob([c], { type: m }); const u = URL.createObjectURL(b); const a = document.createElement('a'); a.href = u; a.download = f; a.click(); URL.revokeObjectURL(u) }

function AppContent() {
  // ─── Shared View ──────────────────────────────────
  const [shared, setShared] = useState(null)
  useEffect(() => { const h = window.location.hash; if (h.startsWith('#/share/')) { const d = decodeShare(h.slice(8)); if (d) setShared(d) } }, [])

  // ─── Store (ALL hooks must be before any early return) ───
  const theme = useAppStore(s => s.theme)
  const lang = useAppStore(s => s.lang)
  const fontSize = useAppStore(s => s.fontSize)
  const panelOpen = useAppStore(s => s.panelOpen)
  const detailOpen = useAppStore(s => s.detailOpen)
  const detailTab = useAppStore(s => s.detailTab)
  const view = useAppStore(s => s.view)
  const showSettings = useAppStore(s => s.showSettings)
  const settingsTab = useAppStore(s => s.settingsTab)
  const dataLayers = useAppStore(s => s.dataLayers)
  const events = useAppStore(s => s.events)
  const activeEventId = useAppStore(s => s.activeEventId)
  const mapAnims = useAppStore(s => s.mapAnims)
  const baseLayerId = useAppStore(s => s.baseLayerId)
  const aiProviders = useAppStore(s => s.aiProviders)
  const activeProvider = useAppStore(s => s.activeProvider)
  const activeModel = useAppStore(s => s.activeModel)
  const chatMessages = useAppStore(s => s.chatMessages)
  const sentinel2 = useAppStore(s => s.sentinel2)
  const ae = useActiveEvent()
  const rawIncidents = useRawIncidents()
  const sInc = useMemo(() => [...rawIncidents].sort((a, b) => a.dt.localeCompare(b.dt)), [rawIncidents])

  // ─── Mutations ────────────────────────────────────
  const briefMut = useBriefAnalysis()
  const chatMut = useChatSend()

  // ─── Local UI State ───────────────────────────────
  const [searchQuery, setSearchQuery] = useState('')
  const [inputVal, setInputVal] = useState('')
  const [noteInput, setNoteInput] = useState('')
  const [briefInput, setBriefInput] = useState('')
  const [showArchived, setShowArchived] = useState(false)
  const [showShareModal, setShowShareModal] = useState(false)
  const [shareUrl, setShareUrl] = useState('')
  const [sharePw, setSharePw] = useState('')
  const [sharePwOn, setSharePwOn] = useState(false)
  const [showExportMenu, setShowExportMenu] = useState(false)
  const [copyFb, setCopyFb] = useState('')
  const [showIncForm, setShowIncForm] = useState(false)
  const [incForm, setIncForm] = useState({ ti: '', d: '', tp: 'displacement', s: 'medium', ac: '', og: '', a: null, o: null, drawType: null, drawR: 50 })
  const [mapClickMode, setMapClickMode] = useState(false)
  const [infraLayers, setInfraLayers] = useState({})
  const [infraLoading, setInfraLoading] = useState('')
  const [showAddMenu, setShowAddMenu] = useState(false)
  const [editBriefId, setEditBriefId] = useState(null)
  const [editBriefText, setEditBriefText] = useState('')
  const [editIncId, setEditIncId] = useState(null)
  const [editInc, setEditInc] = useState(null)
  const [busy, setBusy] = useState(false)

  const stR = useRef(null), ceR = useRef(null), cmR = useRef(null), igR = useRef({})
  const mapRefsRef = useRef(null)

  // ─── Effects (must be before early return) ─────────
  useEffect(() => { document.documentElement.setAttribute('data-theme', theme); document.documentElement.classList.toggle('dark', theme === 'dark') }, [theme])
  useEffect(() => { document.documentElement.style.setProperty('--fs', fontSize + 'px') }, [fontSize])
  useEffect(() => { if (ae?.region) setGeoBias(ae.region) }, [activeEventId])
  useEffect(() => { const h = e => { if (stR.current && !stR.current.contains(e.target)) useAppStore.getState().setShowSettings(false) }; document.addEventListener('mousedown', h); return () => document.removeEventListener('mousedown', h) }, [])
  useEffect(() => { const h = e => { if (e.key === 'Escape') { useAppStore.getState().setDetailOpen(false); setShowShareModal(false); setShowExportMenu(false); setShowIncForm(false); setMapClickMode(false); setShowAddMenu(false) } }; window.addEventListener('keydown', h); return () => window.removeEventListener('keydown', h) }, [])
  useEffect(() => { if (view === 'map') window.__cpMapInvalidate?.() }, [view, panelOpen, detailOpen])
  useEffect(() => { ceR.current?.scrollIntoView({ behavior: 'smooth' }) }, [chatMessages])

  // ─── Early return for shared view (AFTER all hooks) ──
  if (shared) return <SharedView data={shared} />

  // ─── Derived ──────────────────────────────────────
  const _ = k => t(k, lang)
  const stats = computeStats(ae)
  const typeCounts = computeTypeCounts(ae)
  const fEvts = events.filter(e => e.name.toLowerCase().includes(searchQuery.toLowerCase()) || (e.brief || '').toLowerCase().includes(searchQuery.toLowerCase()))
  const cMsgs = chatMessages[activeEventId] || [{ role: 'a', text: _('aiWelcome') }]
  const aBriefs = (ae?.briefs || []).filter(b => !b.archived)
  const xBriefs = (ae?.briefs || []).filter(b => b.archived)
  const apiKey = aiProviders.find(p => p.id === activeProvider)?.key || ''
  const aiStatus = apiKey ? 'ready' : 'unconfigured'
  const inp = { padding: '7px 8px', borderRadius: 6, fontSize: 'calc(var(--fs)*.72)', background: 'var(--surface-input)', border: '1px solid var(--border-input)', color: 'var(--text-primary)', fontFamily: 'inherit', outline: 'none', width: '100%' }
  const svB = s => ({ fontSize: 'calc(var(--fs)*.52)', padding: '1px 5px', borderRadius: 3, fontWeight: 700, background: (SEVERITY[s] || SEVERITY.medium).bg, color: (SEVERITY[s] || SEVERITY.medium).color })
  const layerOpts = theme === 'dark' ? [{ id: 'dark', name: 'Navy (no labels)' }, { id: 'darklabel', name: 'Dark (with labels)' }, ...BASE_LAYERS.filter(l => l.id !== 'osm')] : BASE_LAYERS
  const dlDefs = [{ k: 'incidents', l: _('incidents') }, { k: 'access', l: _('noAccess') }, { k: 'risks', l: _('risks') }, { k: 'corridor', l: _('corridor') }]

  // ─── Store Actions (call via getState to avoid stale closures) ──
  const act = useAppStore.getState

  // ─── Handlers ─────────────────────────────────────
  const flyTo = (a, o) => window.__cpMapFlyTo?.(a, o)

  const handleAddBrief = () => { const txt = briefInput.trim(); if (!txt) return; act().addBrief(txt); setBriefInput('') }

  const handleAnalyzeBrief = (txt) => {
    const text = txt || briefInput.trim() || ae?.brief
    if (!text) { act().addChatMessage(activeEventId, 'a', '⚠️ No text. Paste a brief first.'); return }
    briefMut.mutate({ text, eventId: activeEventId })
  }

  const handleSendMsg = () => {
    const msg = inputVal.trim()
    if (!msg || chatMut.isPending) return
    if (!apiKey) { act().addChatMessage(activeEventId, 'u', msg); act().addChatMessage(activeEventId, 'a', '⚠️ Configure API key in Settings → 🤖'); setInputVal(''); return }
    chatMut.mutate({ message: msg, eventId: activeEventId }); setInputVal('')
  }

  const handleTestKey = async () => { setBusy(true); const r = await testAIConnection(); alert(r.success ? `✅ ${activeProvider} connected!` : `❌ ${r.message}`); setBusy(false) }

  const startEditInc = inc => { setEditIncId(inc.id); setEditInc({ ...inc }) }
  const saveEditInc = () => { if (!editInc) return; act().updateIncident(editIncId, editInc); setEditIncId(null); setEditInc(null) }
  const handleDeleteInc = id => { act().deleteIncident(id); setEditIncId(null); setEditInc(null) }

  const genShare = () => { setShareUrl(location.origin + location.pathname + '#/share/' + encodeShare(ae, sharePwOn ? sharePw : '')); setShowShareModal(true) }
  const cpShare = () => { navigator.clipboard.writeText(shareUrl).then(() => { setCopyFb(_('copied')); setTimeout(() => setCopyFb(''), 2000) }) }
  const saveBriefEdit = bid => { act().updateBriefText(bid, editBriefText); setEditBriefId(null) }

  const subInc = () => {
    if (!incForm.ti || incForm.a === null) return
    const ni = { id: 'inc_' + Date.now(), dt: new Date().toISOString().slice(0, 10), a: incForm.a, o: incForm.o, tp: incForm.tp, s: incForm.s, ti: incForm.ti, d: incForm.d, ac: incForm.ac || 'Unknown', og: incForm.og || 'Field' }
    if (incForm.tp === 'displacement' && incForm.d) { const det = autoDetectType(incForm.d); if (det.confidence > 0) ni.tp = det.type }
    act().addIncident(ni)
    if (incForm.drawType === 'circle') { const ev = act().events.find(e => e.id === activeEventId); act().updateEvent(activeEventId, { drawings: [...(ev?.drawings || []), { type: 'circle', a: incForm.a, o: incForm.o, r: incForm.drawR * 1000, color: (SEVERITY[incForm.s] || SEVERITY.medium).color, label: incForm.ti }] }) }
    flyTo(ni.a, ni.o)
    if (cmR.current && mapRefsRef.current?.map) { mapRefsRef.current.map.removeLayer(cmR.current); cmR.current = null }
    setShowIncForm(false); setIncForm({ ti: '', d: '', tp: 'displacement', s: 'medium', ac: '', og: '', a: null, o: null, drawType: null, drawR: 50 })
  }

  const loadInfra = async type => {
    const map = mapRefsRef.current?.map, L = mapRefsRef.current?.L
    if (!map || !L) return
    if (igR.current[type]) { map.removeLayer(igR.current[type]); delete igR.current[type]; setInfraLayers(p => { const n = { ...p }; delete n[type]; return n }); return }
    setInfraLoading(type)
    try {
      const q = buildOverpassQuery(type, map.getBounds()); const r = await fetch('https://overpass-api.de/api/interpreter', { method: 'POST', body: 'data=' + encodeURIComponent(q) }); const d = await r.json()
      const g = L.layerGroup(); const col = { hospitals: '#E8553A', water: '#4BA8CC', roads: '#8B7355' }
      ;(d.elements || []).forEach(el => { const lat = el.lat || el.center?.lat, lon = el.lon || el.center?.lon, tags = el.tags || {}; if (type === 'roads' && el.geometry) L.polyline(el.geometry.map(p => [p.lat, p.lon]), { color: col[type], weight: 2, opacity: .6 }).bindPopup(`<b>${tags.name || 'Road'}</b><br>${tags.highway || ''}`).addTo(g); else if (lat && lon) { L.circleMarker([lat, lon], { radius: 7, fillColor: col[type], color: '#FFF', weight: 1, fillOpacity: .9 }).bindPopup(type === 'hospitals' ? `<b>🏥 ${tags.name || 'Hospital'}</b><br>${tags.operator || ''}` : `<b>💧 ${tags.name || type}</b>`).addTo(g); L.circle([lat, lon], { radius: 800, fillColor: col[type], color: col[type], weight: 1, fillOpacity: .06, dashArray: '4 3' }).addTo(g) } })
      g.addTo(map); igR.current[type] = g; setInfraLayers(p => ({ ...p, [type]: true }))
    } catch (e) { console.error(e) }
    setInfraLoading('')
  }

  const noteText = text => { const ps = text.split(/(@[\w-]+)/g); return ps.map((p, i) => { if (p.startsWith('@')) { const inc = (ae?.incidents || []).find(x => x.id === p.slice(1) || x.ti.toLowerCase().includes(p.slice(1).toLowerCase())); if (inc) return <span key={i} onClick={() => flyTo(inc.a, inc.o)} style={{ color: 'var(--accent)', cursor: 'pointer', fontWeight: 600, textDecoration: 'underline dotted' }}>{p}</span> } return <span key={i}>{p}</span> }) }

  const flowData = () => { const nodes = [], links = []; events.forEach((ev, ei) => { const nx = 150 + ei * 280, ny = 60; nodes.push({ id: ev.id, label: ev.name.slice(0, 16), x: nx, y: ny, color: (SEVERITY[ev.severity] || SEVERITY.medium).color, r: 40, type: 'event' }); (ev.incidents || []).forEach((inc, ii) => { const ix = nx - 60 + (ii % 4) * 50, iy = ny + 110 + Math.floor(ii / 4) * 60; const nid = ev.id + '_' + inc.id; nodes.push({ id: nid, label: (ICON_MAP[inc.tp] || '⚠️') + inc.ti.slice(0, 10), x: ix, y: iy, color: (SEVERITY[inc.s] || SEVERITY.medium).color, r: 22, type: 'incident' }); links.push([ev.id, nid]) }); if (ei > 0) links.push([events[ei - 1].id, ev.id]) }); return { nodes, links } }

  // ─── RENDER ───────────────────────────────────────
  return (<div className="app-layout">
{/* ═══ LEFT SIDEBAR ═══ */}
<div className={`panel${panelOpen ? '' : ' collapsed'}`}><div className="sidebar-toggle" onClick={() => act().setPanelOpen(!panelOpen)}>◀</div>
<div style={{ padding: '12px 14px 8px', borderBottom: '1px solid var(--border-subtle)' }}><div style={{ display: 'flex', alignItems: 'center', gap: 8 }}><span style={{ width: 8, height: 8, borderRadius: '50%', background: 'var(--danger)', boxShadow: '0 0 6px var(--danger-glow)' }} /><b style={{ fontSize: 'calc(var(--fs)*.88)', letterSpacing: '.04em' }}>{_('corridorPlanner')}</b><span style={{ fontSize: 'calc(var(--fs)*.48)', color: aiStatus === 'ready' ? 'var(--success)' : 'var(--text-faint)', padding: '2px 6px', borderRadius: 3, fontWeight: 700, marginLeft: 'auto', background: aiStatus === 'ready' ? 'var(--success)11' : 'transparent' }}>{aiStatus === 'ready' ? '🟢' : '⚪'} AI</span></div></div>
{/* Search + Add */}
<div style={{ padding: '8px 14px', display: 'flex', gap: 5, borderBottom: '1px solid var(--border-subtle)' }}><div style={{ flex: 1, position: 'relative' }}><input value={searchQuery} onChange={e => setSearchQuery(e.target.value)} placeholder={_('searchEvents')} style={{ ...inp, paddingLeft: 28 }} /><span style={{ position: 'absolute', left: 9, top: '50%', transform: 'translateY(-50%)', fontSize: 'calc(var(--fs)*.72)', color: 'var(--text-faint)', pointerEvents: 'none' }}>🔍</span></div><div style={{ position: 'relative' }}><button onClick={() => setShowAddMenu(v => !v)} style={{ width: 34, height: 34, borderRadius: 7, border: '1px solid var(--border-input)', background: 'var(--surface-card)', color: 'var(--accent)', cursor: 'pointer', fontSize: 'calc(var(--fs)*1)', fontWeight: 700 }}>+</button>{showAddMenu && <div style={{ position: 'absolute', top: '100%', right: 0, marginTop: 4, background: 'var(--bg-secondary)', border: '1px solid var(--border-primary)', borderRadius: 8, boxShadow: 'var(--shadow-lg)', zIndex: 10, minWidth: 180, overflow: 'hidden', animation: 'fadeIn .15s ease' }}><div style={{ padding: '8px 12px', borderBottom: '1px solid var(--border-subtle)', fontSize: 'calc(var(--fs)*.65)', fontWeight: 700, color: 'var(--text-muted)' }}>{_('newEvent')}</div>{EVENT_TYPES.map(et => <button key={et.id} onClick={() => { act().addEvent(et.id); setShowAddMenu(false) }} style={{ display: 'flex', alignItems: 'center', gap: 8, width: '100%', padding: '8px 12px', border: 'none', background: 'transparent', cursor: 'pointer', fontSize: 'calc(var(--fs)*.7)', color: 'var(--text-secondary)', fontFamily: 'inherit' }} onMouseEnter={e => e.currentTarget.style.background = 'var(--bg-hover)'} onMouseLeave={e => e.currentTarget.style.background = 'transparent'}><span>{et.icon}</span>{et.name}</button>)}</div>}</div></div>
{/* View Toggle + Data Layers */}
<div style={{ padding: '6px 14px', borderBottom: '1px solid var(--border-subtle)', background: 'var(--surface-card)' }}><div style={{ display: 'flex', gap: 4, marginBottom: 5 }}>{['map', 'flow'].map(v => <button key={v} onClick={() => act().setView(v)} style={{ flex: 1, padding: '5px 0', borderRadius: 5, border: 'none', cursor: 'pointer', fontSize: 'calc(var(--fs)*.65)', fontWeight: 600, fontFamily: 'inherit', background: view === v ? 'var(--text-primary)' : 'transparent', color: view === v ? 'var(--bg-secondary)' : 'var(--text-muted)' }}>{v === 'map' ? '🗺️ ' + _('map') : '🔀 ' + _('flow')}</button>)}</div><div style={{ display: 'flex', gap: 3, flexWrap: 'wrap' }}>{dlDefs.map(d => <button key={d.k} onClick={() => act().toggleDataLayer(d.k)} style={{ padding: '2px 6px', borderRadius: 4, cursor: 'pointer', fontSize: 'calc(var(--fs)*.52)', fontFamily: 'inherit', fontWeight: 600, background: dataLayers[d.k] ? 'var(--accent-bg)' : 'transparent', color: dataLayers[d.k] ? 'var(--accent)' : 'var(--text-faint)', border: 'none' }}>{dataLayers[d.k] ? '●' : '○'} {d.l}</button>)}</div>{Object.keys(typeCounts).length > 0 && <div style={{ display: 'flex', gap: 4, marginTop: 4, flexWrap: 'wrap' }}>{Object.entries(typeCounts).map(([tp, c]) => <span key={tp} style={{ fontSize: 'calc(var(--fs)*.5)', padding: '1px 5px', borderRadius: 3, background: 'var(--bg-hover)', color: 'var(--text-muted)' }}>{ICON_MAP[tp] || '⚠️'}{c}</span>)}</div>}</div>
{/* Event List */}
<div style={{ flex: 1, overflowY: 'auto', padding: '6px 8px' }}>{fEvts.length === 0 && <div style={{ textAlign: 'center', padding: 16, color: 'var(--text-faint)' }}>{_('noEvents')}</div>}{fEvts.map(ev => { const et = EVENT_TYPES.find(t => t.id === ev.type); return <div key={ev.id} onClick={() => act().selectEvent(ev.id)} style={{ padding: '10px 12px', borderRadius: 8, cursor: 'pointer', marginBottom: 4, background: ev.id === activeEventId ? 'var(--accent-bg)' : 'transparent', border: '1px solid ' + (ev.id === activeEventId ? 'var(--accent)' : 'var(--border-subtle)') }} onMouseEnter={e => { if (ev.id !== activeEventId) e.currentTarget.style.background = 'var(--bg-hover)' }} onMouseLeave={e => { if (ev.id !== activeEventId) e.currentTarget.style.background = 'transparent' }}><div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>{et && <span style={{ fontSize: 'calc(var(--fs)*.72)' }}>{et.icon}</span>}<b style={{ fontSize: 'calc(var(--fs)*.78)', flex: 1, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{ev.name}</b><span style={svB(ev.severity)}>{ev.severity?.toUpperCase()}</span></div><div style={{ fontSize: 'calc(var(--fs)*.55)', color: 'var(--text-muted)', marginTop: 3, paddingLeft: 20, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{ev.brief || '—'}</div></div> })}</div>
{/* Stats */}
{stats.length > 0 && <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4,1fr)', gap: 3, padding: '6px 10px', borderTop: '1px solid var(--border-subtle)', background: 'var(--surface-card)' }}>{stats.map(s => <div key={s.label} style={{ padding: '5px 2px', borderRadius: 4, textAlign: 'center' }}><div style={{ fontSize: 'calc(var(--fs)*1)', fontWeight: 700, color: s.color }}>{s.value}</div><div style={{ fontSize: 'calc(var(--fs)*.42)', color: 'var(--text-muted)' }}>{s.label}</div></div>)}</div>}
{/* Settings Panel */}
<div ref={stR} style={{ borderTop: '1px solid var(--border-subtle)', position: 'relative' }}><button onClick={() => act().setShowSettings(!showSettings)} style={{ width: '100%', padding: '10px 14px', border: 'none', background: showSettings ? 'var(--accent-bg)' : 'var(--bg-secondary)', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 8, fontFamily: 'inherit', fontSize: 'calc(var(--fs)*.72)', color: 'var(--text-muted)', fontWeight: 600 }}>⚙️ {_('settings')}<span style={{ marginLeft: 'auto', fontSize: 'calc(var(--fs)*.5)', color: 'var(--text-faint)' }}>v4</span></button>
{showSettings && <div style={{ position: 'absolute', bottom: '100%', left: 0, right: 0, maxHeight: '60vh', overflowY: 'auto', background: 'var(--bg-secondary)', border: '1px solid var(--border-primary)', borderBottom: 'none', borderRadius: '12px 12px 0 0', boxShadow: 'var(--shadow-lg)', animation: 'fadeIn .2s ease' }}>
<div style={{ display: 'flex', gap: 2, padding: '8px 12px 0', borderBottom: '1px solid var(--border-subtle)' }}>{[{ id: 'appearance', l: '🎨' }, { id: 'map', l: '🗺️' }, { id: 'ai', l: '🤖' }, { id: 'about', l: 'ℹ️' }].map(tb => <button key={tb.id} onClick={() => act().setSettingsTab(tb.id)} style={{ padding: '5px 10px', border: 'none', background: 'transparent', cursor: 'pointer', fontSize: 'calc(var(--fs)*.82)', fontFamily: 'inherit', color: settingsTab === tb.id ? 'var(--accent)' : 'var(--text-faint)', borderBottom: settingsTab === tb.id ? '2px solid var(--accent)' : '2px solid transparent' }}>{tb.l}</button>)}</div>
<div style={{ padding: '12px 14px' }}>
{settingsTab === 'appearance' && <><div style={{ marginBottom: 12 }}><div style={{ fontSize: 'calc(var(--fs)*.68)', fontWeight: 700, marginBottom: 5 }}>{_('theme')}</div><div style={{ display: 'flex', background: 'var(--surface-card)', borderRadius: 7, overflow: 'hidden' }}>{['light', 'dark'].map(tm => <button key={tm} onClick={() => { act().setTheme(tm); if (tm === 'dark' && baseLayerId === 'osm') act().setBaseLayerId('dark'); if (tm === 'light' && baseLayerId === 'dark') act().setBaseLayerId('osm') }} style={{ flex: 1, padding: '8px 0', border: 'none', cursor: 'pointer', fontFamily: 'inherit', fontWeight: 600, fontSize: 'calc(var(--fs)*.68)', background: theme === tm ? 'var(--accent)' : 'transparent', color: theme === tm ? '#FFF' : 'var(--text-muted)' }}>{tm === 'light' ? '☀️' : '🌙'} {_(tm)}</button>)}</div></div><div style={{ marginBottom: 12 }}><div style={{ display: 'flex', justifyContent: 'space-between' }}><span style={{ fontSize: 'calc(var(--fs)*.65)', fontWeight: 600 }}>{_('fontSize')}</span><span style={{ fontSize: 'calc(var(--fs)*.65)', color: 'var(--text-muted)' }}>{fontSize}px</span></div><input type="range" min="10" max="20" value={fontSize} onChange={e => act().setFontSize(+e.target.value)} style={{ width: '100%', accentColor: 'var(--accent)' }} /></div><label style={{ display: 'flex', alignItems: 'center', gap: 8, fontSize: 'calc(var(--fs)*.68)', cursor: 'pointer', marginBottom: 12 }}><input type="checkbox" checked={mapAnims} onChange={e => act().setMapAnims(e.target.checked)} style={{ accentColor: 'var(--accent)' }} />{_('mapAnims')} {mapAnims ? '✨' : ''}</label><div><div style={{ fontSize: 'calc(var(--fs)*.68)', fontWeight: 700, marginBottom: 5 }}>{_('language')}</div><div style={{ display: 'flex', gap: 3, flexWrap: 'wrap' }}>{LANGS.map(l => <button key={l.id} onClick={() => act().setLang(l.id)} style={{ padding: '5px 10px', borderRadius: 5, border: '1px solid ' + (lang === l.id ? 'var(--accent)' : 'var(--border-primary)'), background: lang === l.id ? 'var(--accent-bg)' : 'transparent', color: lang === l.id ? 'var(--accent)' : 'var(--text-muted)', cursor: 'pointer', fontFamily: 'inherit', fontSize: 'calc(var(--fs)*.65)', fontWeight: 600 }}>{l.name}</button>)}</div></div></>}
{settingsTab === 'map' && <><div style={{ marginBottom: 10 }}><div style={{ fontSize: 'calc(var(--fs)*.68)', fontWeight: 700, marginBottom: 5 }}>{_('baseLayer')}</div>{layerOpts.map(b => <label key={b.id} style={{ display: 'flex', alignItems: 'center', gap: 6, padding: '4px 6px', cursor: 'pointer', fontSize: 'calc(var(--fs)*.68)' }}><input type="radio" name="bl" checked={baseLayerId === b.id} onChange={() => act().setBaseLayerId(b.id)} style={{ accentColor: 'var(--accent)' }} />{b.name}</label>)}</div><label style={{ display: 'flex', alignItems: 'center', gap: 6, padding: '4px 6px', fontSize: 'calc(var(--fs)*.68)', cursor: 'pointer', borderTop: '1px solid var(--border-subtle)', paddingTop: 8 }}><input type="checkbox" checked={sentinel2} onChange={e => act().setSentinel2(e.target.checked)} style={{ accentColor: 'var(--accent)' }} /><b>Sentinel-2</b><span style={{ fontSize: 'calc(var(--fs)*.5)', color: 'var(--text-faint)' }}>(satellite — zoom ≥6)</span></label><div style={{ borderTop: '1px solid var(--border-subtle)', paddingTop: 8, marginTop: 8 }}><div style={{ fontSize: 'calc(var(--fs)*.68)', fontWeight: 700, marginBottom: 3 }}>{_('infra')} — Overpass API</div><div style={{ fontSize: 'calc(var(--fs)*.52)', color: 'var(--text-muted)', marginBottom: 5 }}>Real-time from OpenStreetMap. Zoom in first.</div><div style={{ display: 'flex', gap: 4, flexWrap: 'wrap' }}>{[{ k: 'hospitals', l: _('hospitals'), e: '🏥' }, { k: 'water', l: _('waterPoints'), e: '💧' }, { k: 'roads', l: _('roads'), e: '🛣️' }].map(i => <button key={i.k} onClick={() => loadInfra(i.k)} style={{ padding: '5px 10px', borderRadius: 5, cursor: 'pointer', fontSize: 'calc(var(--fs)*.62)', fontFamily: 'inherit', fontWeight: 600, background: infraLayers[i.k] ? 'var(--accent)' : 'var(--surface-card)', color: infraLayers[i.k] ? '#FFF' : 'var(--text-muted)', border: 'none' }}>{infraLoading === i.k ? <span style={{ display: 'inline-block', width: 12, height: 12, border: '2px solid currentColor', borderTopColor: 'transparent', borderRadius: '50%', animation: 'spin .8s linear infinite' }} /> : i.e} {i.l}</button>)}</div></div></>}
{settingsTab === 'ai' && <><div style={{ fontSize: 'calc(var(--fs)*.62)', fontWeight: 700, marginBottom: 6, textTransform: 'uppercase', color: 'var(--text-muted)' }}>AI Providers</div>{aiProviders.map((prov, pi) => <div key={prov.id} style={{ padding: '8px 10px', borderRadius: 7, marginBottom: 6, border: '1px solid ' + (activeProvider === prov.id ? 'var(--accent)' : 'var(--border-primary)'), background: activeProvider === prov.id ? 'var(--accent-bg)' : 'var(--surface-card)', cursor: 'pointer' }} onClick={() => { act().setActiveProvider(prov.id) }}><div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: prov.key || activeProvider === prov.id ? 4 : 0 }}><span style={{ width: 7, height: 7, borderRadius: '50%', background: prov.key ? '#5AAE7A' : 'var(--text-faint)' }} /><b style={{ flex: 1, fontSize: 'calc(var(--fs)*.7)' }}>{prov.name}</b>{activeProvider === prov.id && <span style={{ fontSize: 'calc(var(--fs)*.48)', padding: '1px 5px', borderRadius: 3, background: 'var(--accent)', color: '#FFF', fontWeight: 700 }}>ACTIVE</span>}</div>{activeProvider === prov.id && <><div style={{ display: 'flex', gap: 3, marginBottom: 4 }}><input type="password" value={prov.key} onClick={e => e.stopPropagation()} onChange={e => { act().updateProviderKey(prov.id, e.target.value) }} placeholder={prov.id === 'anthropic' ? 'sk-ant-...' : prov.id === 'google' ? 'AIza...' : 'API key'} style={{ ...inp, flex: 1, fontFamily: 'monospace', fontSize: 'calc(var(--fs)*.6)' }} /><button onClick={e => { e.stopPropagation(); handleTestKey() }} disabled={!prov.key || busy} style={{ padding: '5px 8px', borderRadius: 5, border: 'none', background: 'var(--surface-card)', color: 'var(--text-secondary)', cursor: prov.key && !busy ? 'pointer' : 'not-allowed', fontFamily: 'inherit', fontSize: 'calc(var(--fs)*.58)', fontWeight: 600 }}>Test</button></div><div style={{ display: 'flex', gap: 2, flexWrap: 'wrap' }}>{prov.models.map(m => <button key={m} onClick={e => { e.stopPropagation(); act().setActiveModel(m) }} style={{ padding: '3px 7px', borderRadius: 4, border: 'none', cursor: 'pointer', fontSize: 'calc(var(--fs)*.55)', fontFamily: 'inherit', fontWeight: 600, background: activeModel === m ? 'var(--accent)' : 'var(--bg-hover)', color: activeModel === m ? '#FFF' : 'var(--text-muted)' }}>{m.split('/').pop().replace(/-/g, ' ')}</button>)}</div></>}</div>)}<div style={{ display: 'flex', alignItems: 'center', gap: 5, marginTop: 8, paddingTop: 6, borderTop: '1px solid var(--border-subtle)' }}><span style={{ width: 6, height: 6, borderRadius: '50%', background: aiStatus === 'ready' ? '#5AAE7A' : 'var(--text-faint)' }} /><span style={{ fontSize: 'calc(var(--fs)*.58)', color: 'var(--text-muted)' }}>{aiStatus === 'ready' ? (aiProviders.find(p => p.id === activeProvider)?.name + ' · ' + activeModel.split('/').pop()) : 'No provider configured'}</span></div></>}
{settingsTab === 'about' && <div style={{ fontSize: 'calc(var(--fs)*.68)', color: 'var(--text-secondary)', lineHeight: 1.8 }}><b>Corridor Planner v4</b><br />Zustand + TanStack Query + Zod<br />EN/TR/FR/AR · Overpass API · Multi-AI<br /><span style={{ fontSize: 'calc(var(--fs)*.52)', color: 'var(--text-faint)' }}>PostGIS migration ready</span></div>}
</div></div>}</div>
</div>

{/* ═══ CANVAS ═══ */}
<div className="canvas">
{!panelOpen && <div onClick={() => act().setPanelOpen(true)} style={{ position: 'absolute', top: '50%', left: 0, transform: 'translateY(-50%)', zIndex: 1100, width: 26, height: 52, background: 'var(--bg-secondary)', border: '1px solid var(--border-primary)', borderLeft: 'none', borderRadius: '0 8px 8px 0', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-muted)', fontSize: 14, boxShadow: 'var(--shadow-sm)' }}>▶</div>}

{view === 'map' && <InteractiveMap mapClickMode={mapClickMode} onMapClick={(a, o) => { setIncForm(p => ({ ...p, a, o })); setMapClickMode(false) }} mapClickMarkerRef={cmR} onMapRefsReady={refs => { mapRefsRef.current = refs }} />}

{view === 'flow' && (() => { const { nodes, links } = flowData(); return <div style={{ width: '100%', height: '100%', background: 'var(--bg-primary)', overflow: 'auto' }}><svg width={Math.max(900, nodes.length * 80)} height={600}>{links.map(([f, tt], i) => { const fn = nodes.find(n => n.id === f), tn = nodes.find(n => n.id === tt); return fn && tn ? <line key={i} x1={fn.x} y1={fn.y} x2={tn.x} y2={tn.y} stroke={fn.color} strokeWidth="1.5" opacity=".3" strokeDasharray="4 3" /> : null })}{nodes.map(n => <g key={n.id} style={{ cursor: 'pointer' }} onClick={() => { if (n.type === 'event') { act().setActiveEventId(n.id); act().setView('map') } }}><circle cx={n.x} cy={n.y} r={n.r + 8} fill={n.color} opacity=".06" /><circle cx={n.x} cy={n.y} r={n.r} fill="var(--bg-secondary)" stroke={n.color} strokeWidth={n.type === 'event' ? 2.5 : 1.5} /><text x={n.x} y={n.y} textAnchor="middle" dominantBaseline="middle" fill="var(--text-primary)" fontSize={n.type === 'event' ? 11 : 8} fontWeight={n.type === 'event' ? 700 : 400} fontFamily="'Source Serif 4',serif">{n.label}</text></g>)}</svg></div> })()}
</div>

{/* ═══ RIGHT DETAIL PANEL ═══ */}
{detailOpen && ae && <div style={{ width: 420, minWidth: 420, display: 'flex', flexDirection: 'column', background: 'var(--bg-secondary)', borderLeft: '1px solid var(--border-primary)', zIndex: 100, overflow: 'hidden' }}>
{/* Header */}
<div style={{ padding: '12px 14px', borderBottom: '1px solid var(--border-subtle)', display: 'flex', alignItems: 'flex-start', gap: 8 }}><div style={{ flex: 1 }}><div style={{ display: 'flex', alignItems: 'center', gap: 5, marginBottom: 3 }}><span style={svB(ae.severity)}>{ae.severity?.toUpperCase()}</span><span style={{ fontSize: 'calc(var(--fs)*.5)', color: 'var(--text-faint)' }}>{ae.status}</span></div><b style={{ fontSize: 'calc(var(--fs)*.88)', display: 'block', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{ae.name}</b></div><div style={{ display: 'flex', gap: 4, flexShrink: 0 }}><button onClick={genShare} style={{ background: 'none', border: '1px solid var(--border-primary)', cursor: 'pointer', color: 'var(--text-muted)', padding: '4px 8px', borderRadius: 5, fontSize: 'calc(var(--fs)*.72)' }}>🔗</button><div style={{ position: 'relative' }}><button onClick={() => setShowExportMenu(v => !v)} style={{ background: 'none', border: '1px solid var(--border-primary)', cursor: 'pointer', color: 'var(--text-muted)', padding: '4px 8px', borderRadius: 5, fontSize: 'calc(var(--fs)*.72)' }}>📥</button>{showExportMenu && <div style={{ position: 'absolute', top: '100%', right: 0, marginTop: 4, background: 'var(--bg-secondary)', border: '1px solid var(--border-primary)', borderRadius: 8, boxShadow: 'var(--shadow-md)', zIndex: 10, minWidth: 150, overflow: 'hidden' }}>{[{ fn: () => { dlF(JSON.stringify(eventToGeoJSON(ae), null, 2), ae.name.replace(/\s+/g, '_') + '.geojson', 'application/geo+json'); setShowExportMenu(false) }, l: '🗺️ GeoJSON' }, { fn: () => { dlF(eventToCSV(ae), ae.name.replace(/\s+/g, '_') + '.csv', 'text/csv'); setShowExportMenu(false) }, l: '📊 CSV' }, { fn: () => { dlF(eventToReport(ae), ae.name.replace(/\s+/g, '_') + '.md'); setShowExportMenu(false) }, l: '📝 Report' }].map(x => <button key={x.l} onClick={x.fn} style={{ display: 'block', width: '100%', padding: '8px 14px', border: 'none', background: 'transparent', cursor: 'pointer', fontSize: 'calc(var(--fs)*.68)', color: 'var(--text-secondary)', fontFamily: 'inherit', textAlign: 'left' }} onMouseEnter={e => e.currentTarget.style.background = 'var(--bg-hover)'} onMouseLeave={e => e.currentTarget.style.background = 'transparent'}>{x.l}</button>)}</div>}</div><button onClick={() => act().setDetailOpen(false)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-muted)', fontSize: 'calc(var(--fs)*1.1)' }}>✕</button></div></div>
{/* Brief strip */}
{ae.brief && detailTab !== 'overview' && <div style={{ padding: '6px 14px', borderBottom: '1px solid var(--border-subtle)', fontSize: 'calc(var(--fs)*.62)', color: 'var(--text-muted)', lineHeight: 1.5, cursor: 'pointer', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }} onClick={() => act().setDetailTab('overview')} title={ae.brief}>📋 {ae.brief.slice(0, 60)}…</div>}
{/* Tabs */}
<div style={{ display: 'flex', borderBottom: '1px solid var(--border-subtle)', padding: '0 4px' }}>{[{ id: 'ai', i: '🤖' }, { id: 'overview', i: '📋 Briefs' }, { id: 'incidents', i: '⚠️' }, { id: 'notebook', i: '📓' }].map(tb => <button key={tb.id} onClick={() => act().setDetailTab(tb.id)} style={{ flex: 1, padding: '8px 2px', border: 'none', background: 'transparent', cursor: 'pointer', fontSize: 'calc(var(--fs)*.68)', fontFamily: 'inherit', color: detailTab === tb.id ? 'var(--accent)' : 'var(--text-faint)', borderBottom: detailTab === tb.id ? '2px solid var(--accent)' : '2px solid transparent' }}>{tb.i}</button>)}</div>
{/* Tab Content */}
<div style={{ flex: 1, overflowY: 'auto', padding: '12px 14px', display: 'flex', flexDirection: 'column' }}>
{/* AI Tab */}
{detailTab === 'ai' && <><div style={{ flex: 1, overflowY: 'auto', display: 'flex', flexDirection: 'column', gap: 6, marginBottom: 8 }}>{cMsgs.map((m, i) => <div key={i} style={{ animation: 'fadeIn .3s ease', maxWidth: '94%', alignSelf: m.role === 'u' ? 'flex-end' : 'flex-start' }}>{m.role === 'a' && <div style={{ fontSize: 'calc(var(--fs)*.5)', color: 'var(--text-faint)', marginBottom: 2 }}>🤖</div>}<div style={{ padding: '8px 10px', borderRadius: 9, fontSize: 'calc(var(--fs)*.75)', lineHeight: 1.7, whiteSpace: 'pre-wrap', wordBreak: 'break-word', ...(m.role === 'u' ? { background: 'var(--surface-msg-user)', color: 'var(--surface-msg-user-text)', borderBottomRightRadius: 3 } : { background: 'var(--surface-msg-ai)', border: '1px solid var(--surface-msg-ai-border)', color: 'var(--surface-msg-ai-text)', borderBottomLeftRadius: 3 }) }}>{m.text}</div></div>)}{(chatMut.isPending || briefMut.isPending) && <div style={{ alignSelf: 'flex-start' }}><div style={{ padding: '8px 10px', borderRadius: 9, background: 'var(--surface-msg-ai)', border: '1px solid var(--surface-msg-ai-border)' }}><span style={{ animation: 'blink 1.2s infinite', color: 'var(--text-muted)' }}>{_('thinking')}</span></div></div>}<div ref={ceR} /></div><div style={{ marginBottom: 6 }}><textarea value={briefInput} onChange={e => setBriefInput(e.target.value)} placeholder={_('uploadBrief')} style={{ ...inp, minHeight: 50, resize: 'vertical', lineHeight: 1.5 }} /><div style={{ display: 'flex', gap: 4, marginTop: 4 }}><button onClick={handleAddBrief} disabled={!briefInput.trim()} style={{ flex: 1, padding: '6px 0', borderRadius: 6, border: 'none', background: 'var(--accent)', color: '#FFF', cursor: briefInput.trim() ? 'pointer' : 'not-allowed', fontFamily: 'inherit', fontSize: 'calc(var(--fs)*.65)', fontWeight: 600, opacity: briefInput.trim() ? 1 : .5 }}>{_('addBrief')}</button><button onClick={() => handleAnalyzeBrief()} disabled={briefMut.isPending} style={{ flex: 1, padding: '6px 0', borderRadius: 6, border: '1px solid var(--accent)', background: 'transparent', color: 'var(--accent)', cursor: !briefMut.isPending ? 'pointer' : 'not-allowed', fontFamily: 'inherit', fontSize: 'calc(var(--fs)*.65)', fontWeight: 600, opacity: briefMut.isPending ? .4 : 1 }}>{briefMut.isPending ? _('analyzing') : _('analyzeMap')}</button></div></div><div style={{ display: 'flex', gap: 5 }}><input value={inputVal} onChange={e => setInputVal(e.target.value)} onKeyDown={e => e.key === 'Enter' && !e.shiftKey && handleSendMsg()} placeholder={apiKey ? 'Ask about this crisis...' : _('notConfigured')} disabled={chatMut.isPending} style={{ ...inp, flex: 1 }} /><button onClick={handleSendMsg} disabled={chatMut.isPending} style={{ padding: '8px 12px', borderRadius: 7, border: 'none', background: chatMut.isPending ? 'var(--text-faint)' : 'var(--text-primary)', color: 'var(--bg-secondary)', cursor: chatMut.isPending ? 'not-allowed' : 'pointer', fontWeight: 700 }}>↵</button></div></>}
{/* Overview / Briefs Tab */}
{detailTab === 'overview' && <><div style={{ display: 'grid', gridTemplateColumns: 'repeat(4,1fr)', gap: 4, marginBottom: 12 }}>{stats.map(s => <div key={s.label} style={{ padding: '6px 2px', borderRadius: 5, textAlign: 'center', background: 'var(--surface-card)', border: '1px solid var(--border-primary)' }}><div style={{ fontSize: 'calc(var(--fs)*1)', fontWeight: 700, color: s.color }}>{s.value}</div><div style={{ fontSize: 'calc(var(--fs)*.45)', color: 'var(--text-muted)' }}>{s.label}</div></div>)}</div><div style={{ marginBottom: 12 }}><div style={{ fontSize: 'calc(var(--fs)*.62)', fontWeight: 700, color: 'var(--text-muted)', marginBottom: 4, textTransform: 'uppercase' }}>📌 Main Brief</div>{ae.brief ? <div style={{ padding: '10px 12px', borderRadius: 7, background: 'var(--surface-card)', border: '1px solid var(--border-primary)', fontSize: 'calc(var(--fs)*.72)', lineHeight: 1.7, color: 'var(--text-secondary)' }}>{ae.brief}</div> : <div style={{ padding: '8px 12px', borderRadius: 7, border: '1px dashed var(--border-primary)', color: 'var(--text-faint)', fontSize: 'calc(var(--fs)*.68)', textAlign: 'center' }}>No main brief yet.</div>}</div><div style={{ marginBottom: 12 }}><textarea value={briefInput} onChange={e => setBriefInput(e.target.value)} placeholder={_('uploadBrief')} style={{ ...inp, minHeight: 50, resize: 'vertical', lineHeight: 1.5, marginBottom: 4 }} /><div style={{ display: 'flex', gap: 4 }}><button onClick={handleAddBrief} disabled={!briefInput.trim()} style={{ flex: 1, padding: '6px 0', borderRadius: 6, border: 'none', background: 'var(--accent)', color: '#FFF', cursor: briefInput.trim() ? 'pointer' : 'not-allowed', fontFamily: 'inherit', fontSize: 'calc(var(--fs)*.62)', fontWeight: 600, opacity: briefInput.trim() ? 1 : .5 }}>{_('addBrief')}</button><button onClick={() => handleAnalyzeBrief()} disabled={briefMut.isPending} style={{ flex: 1, padding: '6px 0', borderRadius: 6, border: '1px solid var(--accent)', background: 'transparent', color: 'var(--accent)', cursor: !briefMut.isPending ? 'pointer' : 'not-allowed', fontFamily: 'inherit', fontSize: 'calc(var(--fs)*.62)', fontWeight: 600 }}>{briefMut.isPending ? _('analyzing') : _('analyzeMap')}</button></div></div><div style={{ marginBottom: 12 }}><div style={{ fontSize: 'calc(var(--fs)*.62)', fontWeight: 700, color: 'var(--text-muted)', marginBottom: 4, textTransform: 'uppercase' }}>{_('briefs')} ({aBriefs.length})</div>{aBriefs.length === 0 && <div style={{ fontSize: 'calc(var(--fs)*.68)', color: 'var(--text-faint)', padding: '8px 0' }}>{_('noBriefs')}</div>}{aBriefs.map(b => <div key={b.id} style={{ padding: '8px 10px', borderRadius: 6, marginBottom: 4, background: 'var(--surface-card)', border: '1px solid var(--border-primary)', fontSize: 'calc(var(--fs)*.72)', lineHeight: 1.6 }}><div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 3 }}><span style={{ fontSize: 'calc(var(--fs)*.5)', color: 'var(--text-faint)' }}>{new Date(b.ts).toLocaleDateString()}</span><div style={{ display: 'flex', gap: 6 }}><button onClick={() => { setEditBriefId(b.id); setEditBriefText(b.text) }} style={{ fontSize: 'calc(var(--fs)*.5)', color: 'var(--accent)', background: 'none', border: 'none', cursor: 'pointer' }}>{_('edit')}</button><button onClick={() => act().archiveBrief(b.id)} style={{ fontSize: 'calc(var(--fs)*.5)', color: 'var(--text-faint)', background: 'none', border: 'none', cursor: 'pointer' }}>{_('archive')}</button><button onClick={() => handleAnalyzeBrief(b.text)} style={{ fontSize: 'calc(var(--fs)*.5)', color: 'var(--accent)', background: 'none', border: 'none', cursor: 'pointer' }}>{_('analyzeMap')}</button></div></div>{editBriefId === b.id ? <div><textarea value={editBriefText} onChange={e => setEditBriefText(e.target.value)} style={{ ...inp, minHeight: 60, resize: 'vertical', marginBottom: 4 }} /><div style={{ display: 'flex', gap: 4 }}><button onClick={() => saveBriefEdit(b.id)} style={{ padding: '4px 10px', borderRadius: 5, border: 'none', background: 'var(--accent)', color: '#FFF', cursor: 'pointer', fontSize: 'calc(var(--fs)*.6)', fontFamily: 'inherit' }}>{_('save')}</button><button onClick={() => setEditBriefId(null)} style={{ padding: '4px 10px', borderRadius: 5, border: '1px solid var(--border-primary)', background: 'transparent', color: 'var(--text-muted)', cursor: 'pointer', fontSize: 'calc(var(--fs)*.6)', fontFamily: 'inherit' }}>{_('cancel')}</button></div></div> : <div style={{ color: 'var(--text-secondary)' }}>{b.text}</div>}</div>)}</div>{xBriefs.length > 0 && <div style={{ marginBottom: 12 }}><button onClick={() => setShowArchived(v => !v)} style={{ fontSize: 'calc(var(--fs)*.58)', color: 'var(--text-faint)', background: 'none', border: 'none', cursor: 'pointer' }}>{showArchived ? '▾' : '▸'} {_('archived')} ({xBriefs.length})</button>{showArchived && xBriefs.map(b => <div key={b.id} style={{ padding: '6px 10px', borderRadius: 5, marginTop: 3, background: 'var(--bg-hover)', borderLeft: '3px solid var(--text-faint)', fontSize: 'calc(var(--fs)*.65)', opacity: .7 }}><div style={{ fontSize: 'calc(var(--fs)*.48)', color: 'var(--text-faint)' }}>{new Date(b.ts).toLocaleDateString()}</div>{b.text}</div>)}</div>}{events.length > 1 ? <button onClick={() => { if (confirm('Delete?')) act().deleteEvent(ae.id) }} style={{ marginTop: 'auto', padding: '7px 0', borderRadius: 7, border: '1px solid var(--danger)', background: 'transparent', color: 'var(--danger)', cursor: 'pointer', fontFamily: 'inherit', fontSize: 'calc(var(--fs)*.65)', fontWeight: 600, width: '100%' }}>🗑️ {_('deleteEvent')}</button> : null}</>}
{/* Incidents Tab */}
{detailTab === 'incidents' && <>{showIncForm && <div style={{ padding: 12, borderRadius: 8, border: '1px solid var(--accent)', background: 'var(--accent-bg)', marginBottom: 10, animation: 'fadeIn .2s ease' }}><div style={{ fontSize: 'calc(var(--fs)*.72)', fontWeight: 700, marginBottom: 8 }}>{_('reportIncident')}</div><input value={incForm.ti} onChange={e => setIncForm(p => ({ ...p, ti: e.target.value }))} placeholder={_('incTitle')} style={{ ...inp, marginBottom: 5 }} /><input value={incForm.d} onChange={e => setIncForm(p => ({ ...p, d: e.target.value }))} placeholder={_('incDesc')} style={{ ...inp, marginBottom: 5 }} /><div style={{ display: 'flex', gap: 5, marginBottom: 5 }}><select value={incForm.tp} onChange={e => setIncForm(p => ({ ...p, tp: e.target.value }))} style={{ ...inp, flex: 1 }}>{INC_TYPES.map(tp => <option key={tp} value={tp}>{ICON_MAP[tp] || '⚠️'} {tp}</option>)}</select><select value={incForm.s} onChange={e => setIncForm(p => ({ ...p, s: e.target.value }))} style={{ ...inp, flex: 1 }}>{SEV_LEVELS.map(s => <option key={s} value={s}>{s.toUpperCase()}</option>)}</select></div><div style={{ display: 'flex', gap: 5, marginBottom: 5 }}><input value={incForm.ac} onChange={e => setIncForm(p => ({ ...p, ac: e.target.value }))} placeholder="Actor" style={{ ...inp, flex: 1 }} /><input value={incForm.og} onChange={e => setIncForm(p => ({ ...p, og: e.target.value }))} placeholder="Organization" style={{ ...inp, flex: 1 }} /></div><button onClick={() => setMapClickMode(true)} style={{ width: '100%', padding: '7px 0', borderRadius: 6, border: '1px dashed var(--accent)', background: 'transparent', color: 'var(--accent)', cursor: 'pointer', fontFamily: 'inherit', fontSize: 'calc(var(--fs)*.68)', fontWeight: 600, marginBottom: 5 }}>{incForm.a !== null ? `📍 ${incForm.a}, ${incForm.o}` : _('clickMap')}</button><label style={{ display: 'flex', alignItems: 'center', gap: 6, fontSize: 'calc(var(--fs)*.65)', cursor: 'pointer', marginBottom: 5 }}><input type="checkbox" checked={incForm.drawType === 'circle'} onChange={e => setIncForm(p => ({ ...p, drawType: e.target.checked ? 'circle' : null }))} style={{ accentColor: 'var(--accent)' }} />{_('drawCircle')}</label>{incForm.drawType === 'circle' && <div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 5 }}><span style={{ fontSize: 'calc(var(--fs)*.62)' }}>{_('drawRadius')}</span><input type="range" min="10" max="200" value={incForm.drawR} onChange={e => setIncForm(p => ({ ...p, drawR: +e.target.value }))} style={{ flex: 1, accentColor: 'var(--accent)' }} /><span style={{ fontSize: 'calc(var(--fs)*.62)', color: 'var(--text-muted)', minWidth: 35 }}>{incForm.drawR}km</span></div>}<div style={{ display: 'flex', gap: 5 }}><button onClick={subInc} disabled={!incForm.ti || incForm.a === null} style={{ flex: 1, padding: '7px 0', borderRadius: 6, border: 'none', background: 'var(--accent)', color: '#FFF', cursor: incForm.ti && incForm.a !== null ? 'pointer' : 'not-allowed', fontFamily: 'inherit', fontSize: 'calc(var(--fs)*.68)', fontWeight: 600, opacity: incForm.ti && incForm.a !== null ? 1 : .5 }}>{_('addIncident')}</button><button onClick={() => setShowIncForm(false)} style={{ flex: 1, padding: '7px 0', borderRadius: 6, border: '1px solid var(--border-primary)', background: 'transparent', color: 'var(--text-muted)', cursor: 'pointer', fontFamily: 'inherit', fontSize: 'calc(var(--fs)*.68)' }}>{_('cancel')}</button></div></div>}{!showIncForm && <button onClick={() => setShowIncForm(true)} style={{ padding: '8px 0', borderRadius: 7, border: '1px dashed var(--accent)', background: 'transparent', color: 'var(--accent)', cursor: 'pointer', fontFamily: 'inherit', fontSize: 'calc(var(--fs)*.68)', fontWeight: 600, marginBottom: 8, width: '100%' }}>+ {_('reportIncident')}</button>}{sInc.length === 0 && <div style={{ textAlign: 'center', padding: 16, color: 'var(--text-faint)' }}>{_('noIncidents')}</div>}{sInc.map(inc => { const isEdit = editIncId === inc.id && editInc; return <div key={inc.id} data-inc-id={inc.id} style={{ padding: '8px 10px', borderRadius: 7, marginBottom: 4, border: '1px solid ' + (isEdit ? 'var(--accent)' : 'var(--border-primary)'), background: isEdit ? 'var(--accent-bg)' : 'var(--surface-card)', animation: isEdit ? 'fadeIn .2s ease' : 'none' }}>{isEdit ? <div><input value={editInc.ti} onChange={e => setEditInc(p => ({ ...p, ti: e.target.value }))} style={{ ...inp, marginBottom: 4, fontWeight: 600 }} /><input value={editInc.d} onChange={e => setEditInc(p => ({ ...p, d: e.target.value }))} style={{ ...inp, marginBottom: 4 }} /><div style={{ display: 'flex', gap: 4, marginBottom: 4 }}><select value={editInc.tp} onChange={e => setEditInc(p => ({ ...p, tp: e.target.value }))} style={{ ...inp, flex: 1 }}>{INC_TYPES.map(tp => <option key={tp} value={tp}>{ICON_MAP[tp] || '⚠️'} {tp}</option>)}</select><select value={editInc.s} onChange={e => setEditInc(p => ({ ...p, s: e.target.value }))} style={{ ...inp, flex: 1 }}>{SEV_LEVELS.map(s => <option key={s} value={s}>{s.toUpperCase()}</option>)}</select></div><div style={{ display: 'flex', gap: 4, marginBottom: 4 }}><input value={editInc.ac} onChange={e => setEditInc(p => ({ ...p, ac: e.target.value }))} placeholder="Actor" style={{ ...inp, flex: 1 }} /><input value={editInc.og} onChange={e => setEditInc(p => ({ ...p, og: e.target.value }))} placeholder="Org" style={{ ...inp, flex: 1 }} /></div><div style={{ display: 'flex', gap: 4 }}><button onClick={saveEditInc} style={{ flex: 1, padding: '5px 0', borderRadius: 5, border: 'none', background: 'var(--accent)', color: '#FFF', cursor: 'pointer', fontSize: 'calc(var(--fs)*.62)', fontFamily: 'inherit', fontWeight: 600 }}>{_('save')}</button><button onClick={() => handleDeleteInc(inc.id)} style={{ padding: '5px 8px', borderRadius: 5, border: '1px solid var(--danger)', background: 'transparent', color: 'var(--danger)', cursor: 'pointer', fontSize: 'calc(var(--fs)*.62)', fontFamily: 'inherit' }}>🗑️</button><button onClick={() => { setEditIncId(null); setEditInc(null) }} style={{ flex: 1, padding: '5px 0', borderRadius: 5, border: '1px solid var(--border-primary)', background: 'transparent', color: 'var(--text-muted)', cursor: 'pointer', fontSize: 'calc(var(--fs)*.62)', fontFamily: 'inherit' }}>{_('cancel')}</button></div></div> : <div><div style={{ display: 'flex', alignItems: 'center', gap: 6 }}><span onClick={() => flyTo(inc.a, inc.o)} style={{ cursor: 'pointer' }}>{ICON_MAP[inc.tp] || '⚠️'}</span><b onClick={() => flyTo(inc.a, inc.o)} style={{ flex: 1, fontSize: 'calc(var(--fs)*.72)', cursor: 'pointer' }}>{inc.ti}</b><span style={svB(inc.s)}>{inc.s.toUpperCase()}</span><button onClick={() => startEditInc(inc)} style={{ fontSize: 'calc(var(--fs)*.5)', color: 'var(--accent)', background: 'none', border: 'none', cursor: 'pointer', padding: '2px 4px' }}>✏️</button></div><div style={{ fontSize: 'calc(var(--fs)*.62)', color: 'var(--text-muted)', marginTop: 3, paddingLeft: 24 }}>{inc.d}</div><div style={{ fontSize: 'calc(var(--fs)*.52)', color: 'var(--text-faint)', marginTop: 2, paddingLeft: 24 }}>{inc.dt} · {inc.ac} · {inc.og}</div>{inc._uncertainty && <div style={{ fontSize: 'calc(var(--fs)*.5)', color: 'var(--warning)', marginTop: 2, paddingLeft: 24, fontStyle: 'italic' }}>⚠️ Location uncertain{inc._uncertaintyNote ? ': ' + inc._uncertaintyNote : ''}</div>}</div>}</div> })}<DrawingsList draw={null} onSelect={() => {}} /></>}
{/* Notebook Tab */}
{detailTab === 'notebook' && <><div style={{ flex: 1, overflowY: 'auto' }}>{(!ae.notebook || !ae.notebook.length) && <div style={{ textAlign: 'center', padding: 16, color: 'var(--text-faint)' }}>{_('noNotes')}</div>}{(ae.notebook || []).map(n => <div key={n.id} style={{ padding: '8px 10px', borderRadius: 7, marginBottom: 4, background: 'var(--surface-card)', border: '1px solid var(--border-primary)' }}><div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 3 }}><span style={{ fontSize: 'calc(var(--fs)*.62)', fontWeight: 700, color: 'var(--accent)' }}>{n.author}</span><span style={{ fontSize: 'calc(var(--fs)*.48)', padding: '1px 4px', borderRadius: 3, background: 'var(--accent-bg)', color: 'var(--accent)' }}>{n.type}</span><span style={{ fontSize: 'calc(var(--fs)*.48)', color: 'var(--text-faint)', marginLeft: 'auto' }}>{new Date(n.ts).toLocaleDateString()}</span></div><div style={{ fontSize: 'calc(var(--fs)*.72)', lineHeight: 1.7, color: 'var(--text-secondary)' }}>{noteText(n.text)}</div></div>)}</div><div style={{ display: 'flex', gap: 5 }}><input value={noteInput} onChange={e => setNoteInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && (act().addNote(noteInput), setNoteInput(''))} placeholder={_('addNote')} style={{ ...inp, flex: 1 }} /><button onClick={() => { act().addNote(noteInput); setNoteInput('') }} style={{ padding: '8px 12px', borderRadius: 7, border: 'none', background: 'var(--accent)', color: '#FFF', cursor: 'pointer', fontWeight: 700 }}>+</button></div></>}
</div></div>}
{/* Share Modal */}
{showShareModal && <div style={{ position: 'fixed', inset: 0, zIndex: 9999, display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'rgba(0,0,0,.5)' }} onClick={() => setShowShareModal(false)}><div onClick={e => e.stopPropagation()} style={{ width: 480, maxWidth: '90vw', background: 'var(--bg-secondary)', border: '1px solid var(--border-primary)', borderRadius: 14, padding: '20px 24px', boxShadow: 'var(--shadow-lg)', animation: 'fadeIn .2s ease' }}><div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 14 }}><b style={{ fontSize: 'calc(var(--fs)*.92)' }}>🔗 {_('shareEvent')}</b><button onClick={() => setShowShareModal(false)} style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-muted)', fontSize: 'calc(var(--fs)*1.1)' }}>✕</button></div><div style={{ fontSize: 'calc(var(--fs)*.72)', color: 'var(--text-muted)', marginBottom: 10 }}>{_('shareDesc')}</div><label style={{ display: 'flex', alignItems: 'center', gap: 8, fontSize: 'calc(var(--fs)*.68)', cursor: 'pointer', marginBottom: 10 }}><div onClick={() => setSharePwOn(v => !v)} style={{ width: 36, height: 20, borderRadius: 10, background: sharePwOn ? 'var(--accent)' : 'var(--border-primary)', position: 'relative', cursor: 'pointer', transition: 'background .2s' }}><div style={{ width: 16, height: 16, borderRadius: 8, background: '#FFF', position: 'absolute', top: 2, left: sharePwOn ? 18 : 2, transition: 'left .2s' }} /></div>{_('pwProtect')} <span style={{ color: 'var(--text-faint)', fontSize: 'calc(var(--fs)*.55)' }}>({_('optional')})</span></label>{sharePwOn && <input type="text" value={sharePw} onChange={e => setSharePw(e.target.value)} placeholder={_('password')} style={{ ...inp, marginBottom: 10 }} />}<div style={{ display: 'flex', gap: 6 }}><input readOnly value={shareUrl} style={{ ...inp, flex: 1, fontFamily: 'monospace', fontSize: 'calc(var(--fs)*.6)' }} onFocus={e => e.target.select()} /><button onClick={cpShare} style={{ padding: '8px 16px', borderRadius: 7, border: 'none', background: 'var(--accent)', color: '#FFF', cursor: 'pointer', fontWeight: 700, whiteSpace: 'nowrap' }}>{copyFb || _('copy')}</button></div></div></div>}
</div>)
}

// ─── Root with QueryClientProvider ──────────────────
export default function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <AppContent />
    </QueryClientProvider>
  )
}
